package com.establo.service;
import com.establo.dto.UserDto;import com.establo.entity.*;import com.establo.exception.*;import com.establo.repository.UserRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import java.util.List;
@Service @RequiredArgsConstructor public class UserService {private final UserRepository users;public List<UserDto> all(){return users.findAll().stream().map(this::dto).toList();}public UserDto role(Long id,Role role){var u=entity(id);protectLastAdmin(u,role,false);u.setRole(role);return dto(users.save(u));}public UserDto status(Long id,boolean active){var u=entity(id);protectLastAdmin(u,u.getRole(),!active);u.setActive(active);return dto(users.save(u));}private void protectLastAdmin(User u,Role nextRole,boolean disabling){if(u.getRole()==Role.ADMIN&&users.countByRole(Role.ADMIN)==1&&(nextRole!=Role.ADMIN||disabling))throw new BusinessException("Debe existir al menos un administrador activo");}private User entity(Long id){return users.findById(id).orElseThrow(()->new ResourceNotFoundException("Usuario no encontrado"));}private UserDto dto(User u){return new UserDto(u.getId(),u.getName(),u.getEmail(),u.getRole(),u.isActive());}}
